import org.mockito.Mockito;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    @Test
    public void testWithAllowMissingColumnNames() {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('\"').withQuoteMode(QuoteMode.ALL)
                .withCommentMarker('#').withEscape('\\').withAllowMissingColumnNames(true).withIgnoreEmptyLines(false)
                .withRecordSeparator("\r\n").withNullString("\\N").withHeader((String[]) null).withHeaderComments(null)
                .withSkipHeaderRecord(false).withIgnoreHeaderCase(false).withTrim(false).withTrailingDelimiter(false);

        // When
        CSVFormat result = csvFormat.withAllowMissingColumnNames();

        // Then
        assertTrue(result.getAllowMissingColumnNames());
    }
}
